const SetValue = async (context) => {
    // Helper to format date as MM/DD/YYYY
    const formatDate = (dateValue) => {
        if (!dateValue) return "";

        const date = new Date(dateValue);
        const month = (date.getMonth() + 1).toString().padStart(2, '0');
        const day = date.getDate().toString().padStart(2, '0');
        const year = date.getFullYear();

        return `${month}/${day}/${year}`;
    };

    const projectStage = context?.Form?.Page1?.ProjectStage?.Value || "";
    const projectStatus = context?.Form?.Page1?.ComputedProjectStatus?.Value || "";
    const projectReason = context?.Form?.Page1?.ProjectReason?.Value || "";

    // Early returns - fastest path
    if (projectReason !== "") {
        return formatDate(context?.Form?.Page1?.CanceledDate?.Value);
    }

    if (projectStatus == "Invoiced" || projectStatus.includes("Invoiced")) {
        return formatDate(context?.Form?.ContractorInformationPage?.InvoiceReceivedDate?.Value);
    }

    // Direct field access based on stage
    let dateValue = "";

    if (projectStage == "Lead") {
        dateValue = context?.Form?.Page1?.LeadAssignedDate?.Value || "";
    } else if (projectStage == "Enrollment") {
        dateValue = context?.Form?.Page1?.LeadCompletedDate?.Value || "";
    } else if (projectStage == "Assessment") {
        dateValue = context?.Form?.Page1?.EnrollmentDate?.Value || "";
    } else if (projectStage == "Installation") {
        if (projectStatus == "Installed") {
            dateValue = context?.Form?.Page1?.InstallationCompletedDate?.Value || "";
